var e=JSON.parse(`[{"id":"L3_1","type":"narration","speaker":null,"text":{"KOREA":"어둠 속에서, 무엇인가가 울부짖는 소리가 들렸다.","JPN":"暗闇の中で、何かが泣き叫ぶ声を聞いた。","ENG":"In darkness, I hear the cry of something.","TWN":"我聽見，黑暗中有什麼東西在哭喊。"},"stage":{"bg":"BLACK","slots":{"L":null,"C":null,"R":null}}},{"id":"L4_1","type":"narration","speaker":null,"text":{"KOREA":"만족하면서도 아쉬워하는 듯한.","JPN":"満足しているような、残念がっているような。","ENG":"A cry that was...","TWN":"似是滿足又些許遺憾的感覺。"},"stage":{"bg":"BLACK","slots":{"L":null,"C":null,"R":null}}},{"id":"L5_1","type":"narration","speaker":null,"text":{"KOREA":"그런 울음소리였다.","JPN":"そんな泣き声だった。","ENG":"Content, yet sad.","TWN":"就是那樣的哭喊。"},"stage":{"bg":"BLACK","slots":{"L":null,"C":null,"R":null}}},{"id":"L7_1","type":"dialog","speaker":null,"text":{"KOREA":"저는 알고 있습니다.","JPN":"私は知っていますよ。","ENG":"I know.","TWN":"我知道。"},"stage":{"bg":"BLACK","slots":{"L":null,"C":null,"R":null}}},{"id":"L8_1","type":"dialog","speaker":null,"text":{"KOREA":"당신의 노력과, 죄와, 절망을.","JPN":"君の努力と、罪と、絶望を。","ENG":"Your efforts, sins, and despair.","TWN":"那是你的努力、罪惡、絕望，"},"stage":{"bg":"BLACK","slots":{"L":null,"C":null,"R":null}}},{"id":"L9_1","type":"dialog","speaker":null,"text":{"KOREA":"그리고 그럼에도 놓지 못했던 희망을.","JPN":"そして、それでも結局諦められなかった希望を。","ENG":"Nevertheless, you never let go of hope.","TWN":"還有即便如此也沒放棄的希望。"},"stage":{"bg":"BLACK","slots":{"L":null,"C":null,"R":null}}},{"id":"L13_1","type":"dialog","speaker":"KING_REPLACER_NULL_NULL","text":{"KOREA":"나는……. 아직 죽지 않았군.","JPN":"私は……まだ死んでいないのか。","ENG":"I'm... not dead yet.","TWN":"我……還沒死啊。"},"stage":{"bg":"VOID","slots":{"L":null,"C":{"char_id":"SYSOP_EP9HALF_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"SYSOP_EP9HALF_NULL_NULL","text":{"KOREA":"정확히는 영원에 가깝게 죽어가고 있었죠.","JPN":"正確にはほぼ永遠の死に向かっていました。","ENG":"To be exact, you are dying close to eternity.","TWN":"準確地說，你快要死掉了，永遠地。"},"stage":{"bg":"VOID","slots":{"L":null,"C":{"char_id":"SYSOP_EP9HALF_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"SYSOP_EP9HALF_NULL_NULL","text":{"KOREA":"허수공간에서 관측자가 부재하게 되면 그 순간에 영원히 갇힐 수도 있으니까요.","JPN":"虚数空間で観測者が不在になると、その瞬間に永遠に閉じ込められることもありますからね。","ENG":"When the observer of the imaginary space is absent, you will be trapped in here forever.","TWN":"一旦虛數空間裡沒有了觀測者，你就有可能永遠被困在那一瞬間。"},"stage":{"bg":"VOID","slots":{"L":null,"C":{"char_id":"SYSOP_EP9HALF_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"KING_REPLACER_NULL_NULL","text":{"KOREA":"……누구냐, 너는.","JPN":"……誰だ、お前は。","ENG":"...Who are you?","TWN":"……你是誰。"},"stage":{"bg":"VOID","slots":{"L":null,"C":{"char_id":"SYSOP_EP9HALF_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"SYSOP_EP9HALF_NULL_NULL","text":{"KOREA":"혹시나 해서 말씀드리지만, 저에 대해 물어보셔도 대답해 드릴 수 없습니다.","JPN":"念のために言っておきますが、私について聞かれてもお答えできません。","ENG":"Fair warning. I cannot answer the questions you have about me.","TWN":"我話先說在前頭，即使你問了關於我的事，我也不能回答你。"},"stage":{"bg":"VOID","slots":{"L":null,"C":{"char_id":"SYSOP_EP9HALF_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"SYSOP_EP9HALF_NULL_NULL","text":{"KOREA":"당신이 보고 계실 저는 단파 통신으로 보낸 홀로그램에 불과할 테니까요.","JPN":"君が見ている私は、ただの短波通信で作り出されたホログラムに過ぎないでしょうから。","ENG":"For what you see in front of you is a hologram transmitted via shortwave communication.","TWN":"因為你看到的我，只不過是透過短波通訊發送的全息圖。"},"stage":{"bg":"VOID","slots":{"L":null,"C":{"char_id":"SYSOP_EP9HALF_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"KING_REPLACER_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"VOID","slots":{"L":null,"C":{"char_id":"SYSOP_EP9HALF_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"KING_REPLACER_NULL_NULL","text":{"KOREA":"왜, 나를 찾아왔나?","JPN":"なぜ、私の前に現れた？","ENG":"Why are you talking to me?","TWN":"為什麼，來找我？"},"stage":{"bg":"VOID","slots":{"L":null,"C":{"char_id":"SYSOP_EP9HALF_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"SYSOP_EP9HALF_NULL_NULL","text":{"KOREA":"당신이 용서받을 수도, 구원받을 수도 없는 구제불능의 죄인이기 때문입니다.","JPN":"君が許されることも、救われることもできない、救いようのない罪人だからです。","ENG":"Because you are a sinner beyond forgiveness nor salvation.","TWN":"因為你是既不能被原諒，也不無法被救贖的無可救藥之罪人。"},"stage":{"bg":"VOID","slots":{"L":null,"C":{"char_id":"SYSOP_EP9HALF_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"KING_REPLACER_NULL_NULL","text":{"KOREA":"그래서, 심판이라도 내리려고 온 건가……?","JPN":"それで、裁きにでも来たというのか……？","ENG":"So, are you here to sentence me...?","TWN":"所以，你是來審判我的嗎……？"},"stage":{"bg":"VOID","slots":{"L":null,"C":{"char_id":"SYSOP_EP9HALF_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"SYSOP_EP9HALF_NULL_NULL","text":{"KOREA":"그렇지만 동시에 다른 누군가를 한 걸음 더 밀어 줄 수도 있는 분이죠.","JPN":"ところが、同時に君は誰かの背中を押してあげることもできる存在。","ENG":"But at the same time, you are someone who can nudge others to take the next step.","TWN":"不過同樣你也可以推別人一把。"},"stage":{"bg":"VOID","slots":{"L":null,"C":{"char_id":"SYSOP_EP9HALF_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"SYSOP_EP9HALF_NULL_NULL","text":{"KOREA":"이제 곧 죽음을 맞이할 당신에게는 아무런 의미도 없겠지만요.","JPN":"もうすぐ死ぬ君には何の意味もないことではありますが。","ENG":"Maybe it will be meaningless as you are awaiting your inevitable death...","TWN":"即使這對於將要迎來死亡的你來說是沒有任何意義的。"},"stage":{"bg":"VOID","slots":{"L":null,"C":{"char_id":"SYSOP_EP9HALF_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"KING_REPLACER_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"VOID","slots":{"L":null,"C":{"char_id":"SYSOP_EP9HALF_NULL_NULL","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};